/**
 * Returns a random word. Avoids repeating the immediately previous word so
 * a player never has to memorise "apple, apple" back to back.
 */
export function randomWord(previous?: string): string {
  let word = WORDS[Math.floor(Math.random() * WORDS.length)];
  if (previous && WORDS.length > 1) {
    while (word === previous) {
      word = WORDS[Math.floor(Math.random() * WORDS.length)];
    }
  }
  return word;
}
